fn solve(nums: Vec<i64>) -> i64 {
    if nums.is_empty() {
        return 0;
    }

    // Constraints: 1 <= nums[i] <= 10^5
    const MAX_VAL: usize = 100000;

    // 1. Identify U: Set of unique values present in nums.
    let mut is_in_u = vec![false; MAX_VAL + 1];
    for &n in nums.iter() {
        let val = n as usize;
        if val <= MAX_VAL {
            is_in_u[val] = true;
        }
    }

    // 2. Initialize D array: D[x] stores the smallest divisor of x found in U.
    // Initialize D[x] = x.
    let mut d: Vec<usize> = (0..=MAX_VAL).collect();

    // 3 & 4. Sieve-like process: Calculate D[x] for all x <= MAX_VAL.
    // Iterate through possible divisors u in U, in ascending order.
    for u in 1..=MAX_VAL {
        if is_in_u[u] {
            // u is a potential smallest divisor. Update all its multiples x.
            // Since we iterate u increasingly, the first time we set d[x] based on u,
            // u is the smallest divisor in U found so far.
            let mut x = u;
            while x <= MAX_VAL {
                d[x] = u;
                x += u;
            }
        }
    }

    // 5. Calculate the final sum.
    let mut total_sum: i64 = 0;
    for &n in nums.iter() {
        let n_val = n as usize;
        // We rely on the constraint that n_val <= MAX_VAL, so d[n_val] is valid.
        let min_divisor = d[n_val] as i64;
        total_sum += min_divisor;
    }

    total_sum
}
