use std::collections::HashSet;

fn solve(nums: Vec<i64>) -> i64 {
    if nums.is_empty() {
        return 0;
    }

    // Maximum possible value for an element
    let v_max: i64 = 100000;

    // 1. Find the set S of unique values in nums.
    let mut s_set: HashSet<i64> = HashSet::new();
    for &n in &nums {
        s_set.insert(n);
    }

    // 2. Convert S to a sorted list s_1, s_2, ..., s_k.
    let mut s_vec: Vec<i64> = s_set.into_iter().collect();
    s_vec.sort_unstable();

    // M[v] stores the minimum achievable value for an initial element v.
    // Size is V_max + 1.
    let mut m: Vec<i64> = vec![0; (v_max + 1) as usize];

    // Initialize M[s] = s for all s in S.
    for &s in s_vec.iter() {
        m[s as usize] = s;
    }

    // 3 & 4. Dynamic Programming: Update M based on divisibility chain among S.
    for &x in s_vec.iter() {
        let x_usize = x as usize;
        let mut min_achievable = x;

        // Find divisors d of x. Iterate up to sqrt(x).
        let mut d = 1;
        while d * d <= x {
            if x % d == 0 {
                // Check divisor d
                if s_set.contains(&d) {
                    // d is a divisor and is an initial element. We can reduce x to M[d].
                    min_achievable = min_achievable.min(m[d as usize]);
                }

                // Check divisor d2 = x/d
                let d2 = x / d;
                if d2 != d && s_set.contains(&d2) {
                    // d2 is a divisor and is an initial element. We can reduce x to M[d2].
                    min_achievable = min_achievable.min(m[d2 as usize]);
                }
            }
            d += 1;
        }

        // Update M[x] to its minimum achievable value.
        m[x_usize] = min_achievable;
    }

    // 5. Calculate the total minimum sum.
    let mut total_sum: i64 = 0;
    for &x in nums.iter() {
        total_sum += m[x as usize];
    }

    total_sum
}
